function GuessYourSign() {
const [step, setStep] = useState(0);
const [currentSign, setCurrentSign] = useState(null);
const [clueIndex, setClueIndex] = useState(0);
const [guess, setGuess] = useState(null);
const [score, setScore] = useState({correct:0,total:0});
const [feedback, setFeedback] = useState(null);
const allSigns = Object.keys(guessClues);
const startGame = () => { const s=allSigns[Math.floor(Math.random()*allSigns.length)]; setCurrentSign(s);setClueIndex(0);setGuess(null);setFeedback(null);setStep(1); };
const nextClue = () => { if(clueIndex<guessClues[currentSign].length-1)setClueIndex(i=>i+1); };
const makeGuess = (g) => { setGuess(g); const correct=g===currentSign; setScore(s=>({correct:s.correct+(correct?1:0),total:s.total+1})); setFeedback(correct?"Correct! "+currentSign+" energy is undeniable.":"Not quite -- this was "+currentSign+" "+(emojis[currentSign]||"")); setStep(2); };
if(step===0)return(<div style={{animation:"up .5s ease",textAlign:"center",paddingTop:20}}><div style={{fontSize:48,marginBottom:16}}>🔮</div><h2 style={{fontFamily:"'Cinzel',serif",fontWeight:900,fontSize:26,color:"#f5c842",marginBottom:12}}>Guess Your Sign</h2><p style={{fontFamily:"Georgia,serif",color:"#a8e060",fontSize:16,marginBottom:32}}>Read the clues. Guess the zodiac sign. How well do you know the signs?</p><button className="rb" style={{"--a":"#e8a800"}} onClick={startGame}>✦ START GUESSING</button>{score.total>0&&<p style={{fontFamily:"'Cinzel',serif",fontWeight:700,fontSize:11,color:"#f5c842",marginTop:20}}>Score: {score.correct}/{score.total}</p>}</div>);
if(step===1)return(<div style={{animation:"up .5s ease"}}><div style={{background:"rgba(255,200,50,0.06)",border:"1px solid rgba(255,200,50,0.25)",borderRadius:20,padding:"28px 24px",marginBottom:20,position:"relative",overflow:"hidden"}}><div style={{position:"absolute",top:0,left:0,right:0,height:2,background:"linear-gradient(90deg,transparent,#e8a800,transparent)"}}/><div style={{fontFamily:"'Cinzel',serif",fontWeight:700,fontSize:9,letterSpacing:".2em",color:"#a8e060",marginBottom:16}}>CLUE {clueIndex+1} OF {guessClues[currentSign].length}</div><p style={{fontFamily:"Georgia,serif",fontWeight:700,fontSize:20,color:"#ffffff",lineHeight:1.6,margin:"0 0 20px"}}>"{guessClues[currentSign][clueIndex]}"</p>{clueIndex<guessClues[currentSign].length-1&&(<button onClick={nextClue} style={{background:"none",border:"1px solid rgba(168,224,96,0.3)",color:"#a8e060",padding:"8px 20px",borderRadius:"100px",fontFamily:"'Cinzel',serif",fontWeight:700,fontSize:10,cursor:"pointer",letterSpacing:".1em"}}>NEXT CLUE -&gt;</button>)}</div><div style={{fontFamily:"'Cinzel',serif",fontWeight:700,fontSize:10,letterSpacing:".15em",color:"#f5c842",marginBottom:12}}>YOUR GUESS:</div><div style={{display:"grid",gridTemplateColumns:"repeat(3,1fr)",gap:8}}>{allSigns.map(s=>(<button key={s} className="sb" style={{"--a":colors[s]}} onClick={()=>makeGuess(s)}><div style={{fontSize:14,marginBottom:2}}>{emojis[s]||"★"}</div><div style={{fontSize:9,fontWeight:700}}>{s}</div></button>))}</div></div>);
if(step===2)return(<div style={{animation:"up .5s ease",textAlign:"center"}}><div style={{background:guess===currentSign?"rgba(168,224,96,0.08)":"rgba(255,80,80,0.08)",border:"1px solid "+(guess===currentSign?"rgba(168,224,96,0.4)":"rgba(255,100,100,0.3)"),borderRadius:20,padding:"32px 24px",marginBottom:24}}><div style={{fontSize:40,marginBottom:12}}>{emojis[currentSign]||"★"}</div><p style={{fontFamily:"'Cinzel',serif",fontWeight:700,fontSize:18,color:guess===currentSign?"#a8e060":"#f5c842",margin:"0 0 8px"}}>{feedback}</p><p style={{fontFamily:"'Cinzel',serif",fontWeight:700,fontSize:10,letterSpacing:".15em",color:"#f5c842",margin:0}}>SCORE: {score.correct}/{score.total}</p></div><button className="rb" style={{"--a":"#e8a800"}} onClick={startGame}>✦ PLAY AGAIN</button></div>);
}

